mapper.select:
SELECT id, game_id, category_id, title, content, view_count, created_at, updated_at
FROM guide
WHERE id = #{id}

SELECT g.id, g.game_id, gm.name AS game_name, g.category_id, c.name AS category_name, g.title, g.content, g.view_count, g.created_at, g.updated_at FROM guide g LEFT JOIN game gm ON g.game_id = gm.id LEFT JOIN category c ON g.category_id = c.id
AND (g.title ILIKE CONCAT('%', #{keyword}, '%') OR g.content ILIKE CONCAT('%', #{keyword}, '%'))
AND g.game_id = #{gameId}
AND g.category_id = #{categoryId}
ORDER BY g.created_at DESC

mapper.update:
UPDATE guide
SET view_count = view_count + 1
WHERE id = #{id}
